import sys
import os
import re

def check_file(filename):
    if not os.path.exists(filename):
        print('File not found: {}'.format(filename))
        return False
    return True

def read_input(filename):
    with open(filename, 'r') as f:
        input_data = f.read()
    return input_data

def check_output(input_data, output_data):
    input_data = input_data.strip().split('\n')
    output_data = output_data.strip().split('\n')
    if len(input_data) != len(output_data):
        print('Number of lines in input and output do not match')
        return False
    for i in range(len(input_data)):
        if input_data[i].strip() != output_data[i].strip():
            print('Line {} does not match'.format(i+1))
            return False
    return True

def main():
    if len(sys.argv) != 3:
        print('Usage: python check.py input_file output_file')
        return
    input_file = sys.argv[1]
    output_file = sys.argv[2]
    if not check_file(input_file):
        return
    if not check_file(output_file):
        return
    input_data = read_input(input_file)
    output_data = read_input(output_file)
    if not check_output(input_data, output_data):
        return
    print('OK')

if __name__ == '__main__':
    main()
